#include <linux/bpf.h>
#include <linux/if_ether.h>
#include <linux/ip.h>
#include <linux/icmp.h>
#include <bpf/bpf_helpers.h>

// Simple per-flow ICMP echo-request limiter: drop if rate exceeds THRESH_PER_SEC in 1s window
#define THRESH_PER_SEC 30

struct icmp_key {
    __u32 src;  // IPv4 src
    __u32 dst;  // IPv4 dst
};

typedef struct {
    __u64 last_ts_ns;
    __u32 count;
} rate_t;

struct {
    __uint(type, BPF_MAP_TYPE_HASH);
    __uint(max_entries, 1024);
    __type(key, struct icmp_key);
    __type(value, rate_t);
} rates SEC("maps");

SEC("xdp_icmp_rate_limiter")
int xdp_icmp_rate_limiter(struct xdp_md *ctx) {
    void *data = (void *)(long)ctx->data;
    void *data_end = (void *)(long)ctx->data_end;

    struct ethhdr *eth = data;
    if ((void*)(eth + 1) > data_end) return XDP_PASS;
    if (eth->h_proto != __constant_htons(ETH_P_IP)) return XDP_PASS;

    struct iphdr *ip = (void *)eth + sizeof(struct ethhdr);
    if ((void*)(ip + 1) > data_end) return XDP_PASS;
    if (ip->protocol != IPPROTO_ICMP) return XDP_PASS;

    int ip_hdr_len = ip->ihl * 4;
    struct icmphdr *icmp = (void *)ip + ip_hdr_len;
    if ((void*)(icmp + 1) > data_end) return XDP_PASS;

    // Only throttle ICMP echo-requests from 192.168.2.3 to 203.0.113.1
    __u32 src = ip->saddr;
    __u32 dst = ip->daddr;
    // 192.168.2.3 -> 0xC0A80203, 203.0.113.1 -> 0xCB005101 (network order)
    if (src != __constant_htonl(0xC0A80203) || dst != __constant_htonl(0xCB000101)) {
        return XDP_PASS;
    }

    if (icmp->type != ICMP_ECHO) {
        return XDP_PASS;
    }

    struct icmp_key key = { ip->saddr, ip->daddr };
    rate_t *r = rates.lookup(&key);
    __u64 now = bpf_ktime_get_ns();

    if (!r) {
        rate_t newr = { .last_ts_ns = now, .count = 1 };
        rates.update(&key, &newr);
        return XDP_PASS;
    }

    // 1-second window approximation using ns timestamps
    if (now - r->last_ts_ns < 1ul * 1000 * 1000 * 1000) {
        if (++r->count > THRESH_PER_SEC) {
            // drop when over limit
            return XDP_DROP;
        }
        r->last_ts_ns = now;
        rates.update(&key, r);
        return XDP_PASS;
    } else {
        // reset window
        r->last_ts_ns = now;
        r->count = 1;
        rates.update(&key, r);
        return XDP_PASS;
    }
}

